// WF-Val Aggregation: DB-Konsistenz + WF3-Liveness (execution-basiert, nicht verkaufs-basiert)
// WF3 laeuft alle 5 Min und liefert auch ohne Verkaeufe 'success' -> kein Fehlalarm nachts/Wochenende.
const WF3_MAX_SUCCESS_AGE_MIN = 30;  // gesund: letzter ERFOLGREICHER WF3-Lauf juenger als 30 Min

const CHECK_LABELS = {
  keine_preise:     'Aktive Slots ohne Preis',
  negative_qty:     'Negative Lagermengen',
  alte_warnungen:   'Alte ungeloeste Warnungen (>7 Tage)',
  pending_proposals:'Offene Rechnungsvorschlaege (>14 Tage)',
};

// --- DB-Konsistenz-Befunde (leere alwaysOutputData-Items rausfiltern) ---
const otherItems = $('DB - Konsistenzcheck').all().filter(i => i.json && i.json.check_type);
const hasOtherIssues = otherItems.length > 0;

// --- WF3-Liveness aus n8n execution_entity ---
let wf3Unhealthy = false;
let wf3Reason = '';
let wf3Determined = false;
try {
  const row = $('PG n8n - WF3 Execution-Check').first().json;
  const ageRaw = (row && row.wf3_last_success_age_min != null) ? Number(row.wf3_last_success_age_min) : null;
  const lastStatus = (row && row.wf3_last_status) ? row.wf3_last_status : '?';
  if (ageRaw != null && Number.isFinite(ageRaw)) {
    wf3Determined = true;
    if (ageRaw > WF3_MAX_SUCCESS_AGE_MIN) {
      wf3Unhealthy = true;
      wf3Reason = 'Letzter erfolgreicher WF3-Lauf vor ' + Math.round(ageRaw) + ' Min (Limit ' + WF3_MAX_SUCCESS_AGE_MIN + ' Min). Letzter Lauf-Status: ' + lastStatus + '.';
    }
  }
  // ageRaw == null -> Health nicht bestimmbar -> KEINE Aktion (kein Fehlalarm, kein Neustart)
} catch (e) {
  // Execution-Check nicht verfuegbar -> unbestimmt -> keine Aktion
}

const hasIssues = wf3Unhealthy || hasOtherIssues;

if (!hasIssues) {
  return [{ json: {
    status: 'OK', count: 0, has_issues: false,
    restart_flag: 'NEIN',
    wf3_determined: wf3Determined,
    email_subject: null, email_body: null,
    summary: 'Alle Pruefungen bestanden (DB-Konsistenz ok; WF3 ' + (wf3Determined ? 'laeuft' : 'Status unbestimmt') + ').'
  }}];
}

const grouped = {};
for (const { json: r } of otherItems) {
  if (!grouped[r.check_type]) grouped[r.check_type] = [];
  grouped[r.check_type].push(r.message);
}
const otherLines = Object.entries(grouped).map(([type, msgs]) => {
  const label = CHECK_LABELS[type] || type;
  return '<h3 style="color:#c0392b">' + label + ' (' + msgs.length + ')</h3><ul>' +
    msgs.map(m => '<li>' + m + '</li>').join('') + '</ul>';
}).join('');

const wf3Section = wf3Unhealthy
  ? '<h3 style="color:#e67e22">WF3 Verkaufsworkflow haengt - Auto-Neustart ausgeloest</h3><ul><li>' + wf3Reason + '</li></ul>'
  : '';

const ts = new Date().toISOString();
const totalCount = otherItems.length + (wf3Unhealthy ? 1 : 0);

return [{ json: {
  status: 'FEHLER',
  count: totalCount,
  has_issues: true,
  restart_flag: wf3Unhealthy ? 'JA' : 'NEIN',
  wf3_determined: wf3Determined,
  email_subject: '[DB-Check] ' + totalCount + ' Problem' + (totalCount !== 1 ? 'e' : '') + ' - Automatenlager',
  email_body: '<h2 style="color:#c0392b">WF-Val Pruefung: ' + totalCount + ' Problem' + (totalCount !== 1 ? 'e' : '') + '</h2>' + wf3Section + otherLines + '<hr><p style="color:#888;font-size:12px">WF-Val Check: ' + ts + '</p>'
}}];

